import { BackupInfo } from '@eclipse-che/common';
import {
  Alert,
  AlertVariant,
  PageSection,
  PageSectionVariants,
  Spinner,
  Text,
  TextContent,
  TextVariants,
} from '@patternfly/react-core';
import React from 'react';
import { connect, ConnectedProps } from 'react-redux';

import styles from '@/pages/WorkspaceDetails/BackupTab/index.module.css';
import { BackupTabInfo } from '@/pages/WorkspaceDetails/BackupTab/Info';
import { Workspace } from '@/services/workspace-adapter';
import { AppDispatch, RootState } from '@/store';
import { fetchWorkspaceBackupStatus } from '@/store/Backups/actions';
import {
  selectBackupsError,
  selectIsLoadingBackups,
  selectWorkspaceBackupInfo,
} from '@/store/Backups/selectors';

export type OwnProps = {
  workspace: Workspace;
};

export type Props = OwnProps & MappedProps;

export class BackupTab extends React.PureComponent<Props> {
  public componentDidMount(): void {
    this.fetchBackupStatus();
  }

  public componentDidUpdate(prevProps: Props): void {
    if (prevProps.workspace.uid !== this.props.workspace.uid) {
      this.fetchBackupStatus();
    }
  }

  private fetchBackupStatus(): void {
    const { workspace } = this.props;
    this.props.fetchWorkspaceBackupStatus({
      namespace: workspace.namespace,
      workspaceUID: workspace.uid,
      workspaceName: workspace.name,
    });
  }

  public render(): React.ReactElement {
    const { backupInfo, isLoading, error } = this.props;

    if (isLoading && !backupInfo) {
      return (
        <PageSection variant={PageSectionVariants.light}>
          <div className={styles.loading}>
            <Spinner size="lg" aria-label="Loading backup information" />
          </div>
        </PageSection>
      );
    }

    return (
      <PageSection variant={PageSectionVariants.light}>
        <TextContent className={styles.header}>
          <Text component={TextVariants.small}>
            Backup information for this workspace. Backups are created automatically by the
            DevWorkspace Operator based on the cluster configuration.
          </Text>
        </TextContent>

        <div aria-live="polite" aria-atomic="true">
          {error && (
            <Alert
              variant={AlertVariant.danger}
              title="Failed to load backup information"
              isInline
              className={styles.alert}
            >
              {error}
            </Alert>
          )}

          {backupInfo ? (
            <BackupTabInfo
              backupInfo={backupInfo}
              isWorkspaceStopped={this.props.workspace.isStopped}
            />
          ) : (
            !error && (
              <Alert variant={AlertVariant.info} title="No backup information available" isInline>
                Backup data for this workspace has not been recorded yet.
              </Alert>
            )
          )}
        </div>
      </PageSection>
    );
  }
}

const mapStateToProps = (state: RootState, ownProps: OwnProps) => ({
  backupInfo: selectWorkspaceBackupInfo(state, ownProps.workspace.uid) as BackupInfo | undefined,
  isLoading: selectIsLoadingBackups(state),
  error: selectBackupsError(state),
});

const mapDispatchToProps = (dispatch: AppDispatch) => ({
  fetchWorkspaceBackupStatus: (params: {
    namespace: string;
    workspaceUID: string;
    workspaceName: string;
  }) => dispatch(fetchWorkspaceBackupStatus(params)),
});

const connector = connect(mapStateToProps, mapDispatchToProps);

type MappedProps = ConnectedProps<typeof connector>;
export default connector(BackupTab);
